chapterList.requestInfo:
@js:
var host = String(config.host || 'https://m.cuoceng.org');
var u = '';
if (params && params.queryInfo) u = params.queryInfo.url || params.queryInfo.detailUrl || '';
if (!u && typeof result === 'string') u = result;
if (!u && result && result.url) u = result.url;
if (!u && result && result.detailUrl) u = result.detailUrl;
if (!u && params && params.responseUrl) u = params.responseUrl;
u = String(u).trim().split(/\s+/)[0] || '';
if (u.indexOf('/book/chapter/') < 0) {
  var m = u.match(/\/book\/([a-f0-9-]+)\.html/i);
  if (m) u = host + '/book/chapter/' + m[1] + '.html';
}
if (u && u.indexOf('http') !== 0) u = host + u;
return {'url': u, 'httpHeaders': config.httpHeaders};

chapterList.nextPageUrl:
//a[@id='linkNext']/@href||@js:
var cand = String(result || '').trim();
if (!cand) return '';
var cur = String(params.responseUrl || '');
var m1 = cur.match(/\/book\/chapter\/([a-f0-9-]+)(?:\/(\d+))?\.html/i);
var m2 = cand.match(/\/book\/chapter\/([a-f0-9-]+)\/(\d+)\.html/i);
if (!m1 || !m2) return '';
if (m1[1] !== m2[1]) return '';
var curPage = parseInt(m1[2] || '1', 10);
var nextPage = parseInt(m2[2], 10);
if (!nextPage || nextPage <= curPage) return '';
return cand;

chapterContent.requestInfo:
